+fn resolve_datetime_origin_option(
+    origin: Option<&serde_json::Value>,
+) -> Result<Option<fp_frame::ToDatetimeOrigin<'_>>, String> {
+    match origin {
+        None | Some(serde_json::Value::Null) => Ok(None),
