+            let trimmed = value.trim();
+            if trimmed.is_empty() {
+                Err("series_to_datetime datetime_origin must be non-empty".to_owned())
+            } else {
+                Ok(Some(fp_frame::ToDatetimeOrigin::Str(trimmed)))
